    id: 'scrollytelling',
    group: 'coursework',
    title: 'Interactive Scrollytelling Deck',
    text: 'schema driven scrollytelling engine D3 chart library line ridge scatter heatmap maps sankey chord video sections'
  },
  {
    id: 'stride',
    group: 'coursework',
    title: 'Stride Support',
    text: 'customer support copilot MCP tools local LLM FastAPI LM Studio catalog orders complaints recommendations policy QA sentiment'
  },
  {
    id: 'congentra',
    group: 'personal',
    title: 'Congentra',
    text: 'AI native oral verification platform assignment understanding teachers students spoken answers evidence file review academic integrity'
