  {
    id: 'lexaday',
    group: 'personal',
    title: 'Lexaday',
    text: 'daily vocabulary coach generative mnemonics spaced review word roots email Hugging Face images GitHub Actions'
  },
  {
    id: 'dealtracker',
    group: 'personal',
    title: 'Dealtracker',
    text: 'personal deal hunter filters email digests sale pages discounts brands sizes product scrape Gmail'
  },
  {
    id: 'early',
    group: 'personal',
    title: 'My Early Projects in Secondary School',
    text: 'secondary school downloaders browser extensions Kiwiview website economics graph generator Econographer coding club'
  }
];

export default {
  name: 'ProjectsTab',
  mixins: [scrollRevealMixin],
  data() {
    return {
      expanded: { professional: true, coursework: true, personal: true },
      searchQuery: '',
      projectEntries
    };
  },
  computed: {
    searchTerms() {
      return this.searchQuery
        .toLowerCase()
        .split(/[\s,.;:!?()[\]{}"']+/)
        .map((term) => term.trim())
        .filter((term) => term.length >= 2);
    },
    searchActive() {
      return this.searchTerms.length > 0;
    },
    hasSearchMatches() {
      return this.projectEntries.some((entry) => this.entryMatches(entry.id));
    }
  },
  watch: {
    searchQuery() {
      this.refreshScrollReveal();
    }
  },
  mounted() {
    // Returning from a project page (e.g. /projects?to=dealtracker): land directly
    // on that entry, no highlight and no smooth scroll. Re-run once after galleries
    // load so image reflow doesn't leave the position slightly off.
    const to = this.$route.query.to;
    if (!to) return;
    const targetEntry = this.entryById(to);
    if (targetEntry) {
      this.expanded = {
        ...this.expanded,
        [targetEntry.group]: true
      };
    }
    this.$nextTick(() => {
      let tries = 0;
      const jump = () => {
        const el = document.getElementById(to);
        if (el) el.scrollIntoView({ block: 'start' });
        else if (tries++ < 25) setTimeout(jump, 80);
      };
      jump();
      setTimeout(jump, 500);
      // Consume the intent: drop ?to so returning to this entry later (back from
      // another page) restores the saved scroll position instead of re-jumping.
      this.$router.replace({ path: '/projects', query: {} });
    });
  },
  methods: {
    escapeHtml(text) {
      return String(text == null ? '' : text)
        .split('&').join('&amp;')
        .split('<').join('&lt;')
        .split('>').join('&gt;')
        .split(String.fromCharCode(34)).join('&quot;')
        .split("'").join('&#39;');
    },
    escapeRegExp(text) {
      return String(text).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    },
    highlightText(text) {
      const escaped = this.escapeHtml(text);
      const terms = [...new Set(this.searchTerms)]
        .sort((a, b) => b.length - a.length)
        .map((term) => this.escapeRegExp(term));
      if (!terms.length) return escaped;

      const re = new RegExp(`(${terms.join('|')})`, 'gi');
      return escaped.replace(re, '<mark>$1</mark>');
    },
    entryById(id) {
      return this.projectEntries.find((entry) => entry.id === id);
    },
    entryMatches(id) {
      const entry = this.entryById(id);
      if (!entry) return false;
      const text = [entry.title, entry.text].join(' ').toLowerCase();
      return this.searchTerms.every((term) => text.includes(term));
    },
    groupMatches(groupKey) {
      return this.projectEntries
        .filter((entry) => entry.group === groupKey)
        .some((entry) => this.entryMatches(entry.id));
    },
    groupVisible(groupKey) {
      if (!this.searchActive) return true;
      return this.groupMatches(groupKey);
    },
    isGroupExpanded(groupKey) {
      if (this.searchActive) return this.groupMatches(groupKey);
      return this.expanded[groupKey];
    },
    entryVisible(id) {
      if (!this.searchActive) return true;
      return this.entryMatches(id);
    },
    toggleGroup(groupKey) {
      if (this.searchActive) return;
      this.expanded = {
        ...this.expanded,
        [groupKey]: !this.expanded[groupKey]
      };
      this.refreshScrollReveal();
    },
    clearSearch() {
      this.searchQuery = '';
    }
  }
}
</script>

