<template>
  <section class="fragments-page">
    <header class="fragments-hero" data-scroll-reveal>
      <h1>{{ copy.heading }}</h1>
      <p class="fragments-intro">{{ copy.intro }}</p>
      <div class="fragments-controls" aria-label="Fragment tools">
        <button
          class="category-toggle"
          type="button"
          :aria-label="copy.toggleLabel"
          @click="toggleCategory"
        >
          <span class="toggle-frame" :class="{ life: activeCategory === 'life' }">
            <span class="toggle-thumb"></span>
            <span class="toggle-option toggle-ideas">Idea fragments</span>
            <span class="toggle-option toggle-life">Life fragments</span>
          </span>
        </button>
        <label class="fragment-search" aria-label="Search fragments">
          <input
            v-model="searchQuery"
            class="fragment-search-input"
            type="search"
            autocomplete="off"
            spellcheck="false"
            placeholder="Search fragments"
            @keydown.esc.prevent="clearSearch"
          >
          <i class="fa fa-search fragment-search-icon" aria-hidden="true"></i>
        </label>
      </div>
    </header>

    <div class="fragment-list" data-scroll-group data-scroll-step="120">
      <article
        v-for="fragment in filteredFragments"
        :id="fragment.id"
        :key="fragment.id"
        class="fragment-card"
        :class="{ open: isOpen(fragment.id) }"
        data-scroll-reveal
      >
        <div
          class="fragment-summary"
          role="button"
          tabindex="0"
          :aria-expanded="isOpen(fragment.id).toString()"
          @click="toggleFragment(fragment.id)"
          @keydown.enter.prevent="toggleFragment(fragment.id)"
          @keydown.space.prevent="toggleFragment(fragment.id)"
        >
          <h2 v-html="highlightText(fragment.title)"></h2>
          <p class="fragment-teaser" v-html="highlightText(fragment.teaser)"></p>
          <span class="read-cue">
            {{ isOpen(fragment.id) ? copy.close : copy.read }}
            <i class="fas" :class="isOpen(fragment.id) ? 'fa-minus' : 'fa-plus'" aria-hidden="true"></i>
          </span>
        </div>

        <transition name="fragment-expand">
          <div v-if="isOpen(fragment.id)" class="fragment-body">
            <p
              v-for="(paragraph, index) in fragment.body"
              :key="`${fragment.id}-${index}`"
              v-html="highlightText(paragraph)"
            ></p>
          </div>
        </transition>
      </article>
    </div>
    <p v-if="searchActive && !filteredFragments.length" class="fragments-empty">
      No matching fragments.
    </p>
  </section>
</template>

<script>
import { fragments } from '../data/fragments';

function shuffleFragments(items) {
  const shuffled = [...items];

  for (let i = shuffled.length - 1; i > 0; i -= 1) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }

  return shuffled;
}

export default {
  name: 'FragmentsTab',
  data() {
    return {
      activeCategory: 'ideas',
      openIds: [],
      searchQuery: '',
      shuffledFragments: shuffleFragments(fragments)
    };
  },
  computed: {
    ideaFragments() {
      return this.shuffledFragments.filter((fragment) => fragment.category === 'ideas');
    },
    lifeFragments() {
      return this.shuffledFragments.filter((fragment) => fragment.category === 'life');
    },
    copy() {
      return {
        heading: 'Fragments',
        intro: 'Loose fragments of thought and life: notes around mind, language, memory, AI, identity, and ordinary days that stayed with me. Some may later become research, projects, or fuller essays; others are kept here because they still feel more useful as unfinished traces than as closed arguments.',
        read: 'Read',
        close: 'Close',
        toggleLabel: this.activeCategory === 'ideas' ? 'Show life fragments' : 'Show idea fragments'
      };
    },
    filteredFragments() {
      const categoryFragments = this.activeCategory === 'life' ? this.lifeFragments : this.ideaFragments;
      if (this.searchActive) {
        return categoryFragments.filter((fragment) => this.fragmentMatches(fragment));
      }
      return categoryFragments;
    },
    searchActive() {
      return this.searchTerms.length > 0;
    },
    searchTerms() {
      return this.searchQuery
        .toLowerCase()
        .split(/[\s,.;:!?()[\]{}"']+/)
        .map((term) => term.trim())
        .filter((term) => term.length >= 2);
    }
  },
  watch: {
    '$route.hash'() {
      this.activateHashFragment();
    },
    searchQuery() {
      if (this.searchActive) {
        this.openIds = [];
      }
    }
  },
  created() {
    this.activateHashFragment(false);
  },
  mounted() {
    this.activateHashFragment();
    window.addEventListener('hashchange', this.activateHashFragment);
  },
  unmounted() {
    window.removeEventListener('hashchange', this.activateHashFragment);
  },
  methods: {
    currentHashId() {
      const routeHash = this.$route && this.$route.hash ? this.$route.hash : '';
      const browserHash = typeof window !== 'undefined' ? window.location.hash : '';
      let raw = routeHash;

      // In hash-router URLs the browser hash can look like "#/fragments#entry-id".
      // Vue usually exposes the second hash as this.$route.hash, but parse it here too
      // so direct browser/hashchange paths are safe.
      if (!raw && browserHash.startsWith('#/')) {
        const secondHash = browserHash.indexOf('#', 1);
        if (secondHash >= 0) raw = browserHash.slice(secondHash);
      }
      if (!raw) raw = browserHash;
      if (!raw) return '';

      try {
        return decodeURIComponent(raw.replace(/^#/, ''));
      } catch (err) {
        return raw.replace(/^#/, '');
      }
    },
    fragmentById(id) {
      return fragments.find((fragment) => fragment.id === id);
    },
    escapeHtml(text) {
      return String(text == null ? '' : text)
        .split('&').join('&amp;')
        .split('<').join('&lt;')
        .split('>').join('&gt;')
        .split(String.fromCharCode(34)).join('&quot;')
        .split("'").join('&#39;');
    },
    escapeRegExp(text) {
      return String(text).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    },
    fragmentSearchText(fragment) {
      return [
        fragment.title,
        fragment.teaser,
        ...(Array.isArray(fragment.body) ? fragment.body : [])
      ].join(' ').toLowerCase();
    },
    fragmentMatches(fragment) {
      const terms = this.searchTerms;
      if (!terms.length) return false;
      const text = this.fragmentSearchText(fragment);
      return terms.every((term) => text.includes(term));
    },
    highlightText(text) {
      const escaped = this.escapeHtml(text);
      const terms = [...new Set(this.searchTerms)]
        .sort((a, b) => b.length - a.length)
        .map((term) => this.escapeRegExp(term));
      if (!terms.length) return escaped;

      const re = new RegExp(`(${terms.join('|')})`, 'gi');
      return escaped.replace(re, '<mark>$1</mark>');
    },
    clearSearch() {
      this.searchQuery = '';
    },
    activateHashFragment(shouldScroll = true) {
      const id = this.currentHashId();
      if (!id) return;

      const fragment = this.fragmentById(id);
      if (!fragment) return;

      if (fragment.category && this.activeCategory !== fragment.category) {
        this.activeCategory = fragment.category;
      }

      if (!this.openIds.includes(id)) {
        this.openIds = [id];
      }

      if (!shouldScroll) return;

      this.$nextTick(() => {
        this.scrollToHashFragment(id, 0);
      });
    },
    scrollToHashFragment(id, attempt = 0) {
      const el = document.getElementById(id);
      if (el) {
        el.scrollIntoView({ behavior: 'auto', block: 'start' });
        window.dispatchEvent(new Event('scroll'));

        // The body expands through a transition after openIds changes. Re-snap once more
        // so the final layout still lands on the card top.
        if (attempt === 0) {
          window.setTimeout(() => this.scrollToHashFragment(id, 1), 260);
        }
        return;
      }

      if (attempt < 20) {
        window.setTimeout(() => this.scrollToHashFragment(id, attempt + 1), 80);
      }
    },
    toggleCategory() {
      this.activeCategory = this.activeCategory === 'ideas' ? 'life' : 'ideas';
      this.openIds = [];
    },
    isOpen(id) {
      return this.openIds.includes(id);
    },
    toggleFragment(id) {
      if (this.isOpen(id)) {
        this.openIds = this.openIds.filter((openId) => openId !== id);
      } else {
        this.openIds = [...this.openIds, id];
      }
      this.$nextTick(() => window.dispatchEvent(new Event('scroll')));
    }
  }
};
</script>

